// // This module implements a 512x8 bit synchronous memory module that supports both read and write operations. It accepts a read address, a write address, an 8-bit data input, and a write enable signal. Upon the rising edge of the clock, it outputs the data from the read address, and if the write enable signal is active, it stores the data input at the specified write address.
module top_module(

	rdaddr, 
	wraddr, 

	datain,  
	dataout, 

	we, 

	clk
);input [8:0] rdaddr;
	input [8:0] wraddr;

	input      [7:0] datain;
	output reg [7:0] dataout;

	input we;

	input clk;


	reg [7:0] mem[0:511]; 



	always @(posedge clk)
	begin
		dataout <= mem[rdaddr]; 

		if( we ) 
		begin
			mem[wraddr] <= datain;
		end
	end


endmodule
